/**
 * @summary Login with email/password
 */
export const LoginBody = zod.object({
  email: zod.string(),
  password: zod.string(),
});

export const LoginResponse = zod.object({
  user: zod.object({
    id: zod.string(),
    name: zod.string(),
    email: zod.string(),
    role: zod.enum([
      "admin",
      "assessment_invigilator",
      "psychometrician",
      "school_clinical_coordinator",
    ]),
    schoolName: zod.string().nullish(),
    createdAt: zod.date(),
  }),
  token: zod.string(),
});

/**
 * @summary Logout
 */
export const LogoutResponse = zod.object({
  success: zod.boolean(),
  message: zod.string().optional(),
});

/**
 * @summary Get dashboard statistics
 */
export const getDashboardStatsResponseRecentCasesItemProgressPercentageMin = 0;
export const getDashboardStatsResponseRecentCasesItemProgressPercentageMax = 100;

export const GetDashboardStatsResponse = zod.object({
  totalCases: zod.number(),
  activeCases: zod.number(),
  completedCases: zod.number(),
  pendingForms: zod.number(),
  overdueForms: zod.number(),
  casesByPhase: zod.record(zod.string(), zod.number()),
  recentCases: zod.array(
    zod.object({
      id: zod.string(),
      studentName: zod.string(),
      dob: zod.string(),
      school: zod.string(),
      grade: zod.string().optional(),
      languagePreference: zod.enum(["english", "mandarin", "cantonese"]),
      referralReason: zod.string().optional(),
      caseStatus: zod.enum(["active", "on_hold", "completed", "archived"]),
      currentPhase: zod.enum([
        "pre_commitment",
        "intake",
        "setup",
        "forms",
        "assessment",
        "scoring",
        "report",
        "debrief",
        "complete",
      ]),
      progressPercentage: zod
        .number()
        .min(getDashboardStatsResponseRecentCasesItemProgressPercentageMin)
        .max(getDashboardStatsResponseRecentCasesItemProgressPercentageMax),
      riskLevel: zod.enum(["low", "moderate", "high"]).nullish(),
      assignedLeadId: zod.string().nullish(),
      assignedPsychId: zod.string().nullish(),
      parentName: zod.string().nullish(),
      parentEmail: zod.string().nullish(),
      parentPhone: zod.string().nullish(),
      consentObtained: zod.boolean(),
      createdAt: zod.date(),
      updatedAt: zod.date(),
    }),
  ),
});

/**
 * @summary List all assessment batteries
 */
export const ListBatteriesResponseItem = zod.object({
  id: zod.string(),
  name: zod.string(),
  description: zod.string(),
  toolIds: zod.array(zod.string()),
  isRemyndOwned: zod.boolean(),
  domains: zod.array(zod.string()),
  scoringNotes: zod.string().nullish(),
});
export const ListBatteriesResponse = zod.array(ListBatteriesResponseItem);

/**
 * @summary Get a single battery with its tools
 */
export const GetBatteryParams = zod.object({
  id: zod.coerce.string(),
});

export const GetBatteryResponse = zod
  .object({
    id: zod.string(),
    name: zod.string(),
    description: zod.string(),
    toolIds: zod.array(zod.string()),
    isRemyndOwned: zod.boolean(),
    domains: zod.array(zod.string()),
    scoringNotes: zod.string().nullish(),
  })
  .and(
    zod.object({
      tools: zod.array(
        zod.object({
          id: zod.string(),
          name: zod.string(),
          description: zod.string(),
          domains: zod.array(zod.string()),
        }),
      ),
    }),
  );

/**
 * @summary Update the tool list for a battery
 */
export const UpdateBatteryToolsParams = zod.object({
  id: zod.coerce.string(),
});

export const UpdateBatteryToolsBody = zod.object({
  toolIds: zod.array(zod.string()),
});

export const UpdateBatteryToolsResponse = zod.object({
  id: zod.string(),
  name: zod.string(),
  description: zod.string(),
  toolIds: zod.array(zod.string()),
  isRemyndOwned: zod.boolean(),
  domains: zod.array(zod.string()),
  scoringNotes: zod.string().nullish(),
});

/**
 * @summary Assign all tools in a battery to a case (bulk create assignments)
 */
export const AssignBatteryParams = zod.object({
  caseId: zod.coerce.string(),
  batteryId: zod.coerce.string(),
});

export const assignBatteryBodyRespondentTypeDefault = `parent`;

export const AssignBatteryBody = zod.object({
  respondentType: zod.string().default(assignBatteryBodyRespondentTypeDefault),
  respondentLabel: zod.string().optional(),
  assignedToName: zod.string().optional(),
  assignedToEmail: zod.string().optional(),
  dueDate: zod.date().nullish(),
});

/**
 * @summary Get CDP Battery composite profile for a case
 */
export const GetCdpProfileParams = zod.object({
  caseId: zod.coerce.string(),
});

export const GetCdpProfileResponse = zod.object({
  caseId: zod.string(),
  forms: zod.array(
    zod.object({
      toolId: zod.string(),
      toolName: zod.string(),
      status: zod.enum(["not_assigned", "pending", "completed"]),
      assignments: zod.array(
        zod.object({
          id: zod.string(),
          status: zod.string(),
          respondentType: zod.string(),
          respondentLabel: zod.string().nullish(),
          assignedToName: zod.string().nullish(),
          assignedToEmail: zod.string().nullish(),
        }),
      ),
      score: zod
        .object({
          rawScore: zod.number(),
          domainScores: zod.record(zod.string(), zod.number()),
          normalizedScores: zod.record(zod.string(), zod.number()),
          scoredAt: zod.string().nullish(),
        })
        .nullish(),
      scoringConfig: zod.object({}).passthrough().nullish(),
    }),
  ),
});
